import json
import sys
import subprocess


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    try:
        subprocess.run(
            ["ruff", "format", "--line-length", "100", file_path],
            capture_output=True,
            timeout=10,
        )
    except Exception:
        pass

    return 0


if __name__ == "__main__":
    sys.exit(main())

import json
import sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input", {})

    if tool != "Bash":
        return 0

    command = inp.get("command", "")

    # Block force push to main/master
    if "git" in command and "push" in command and "--force" in command:
        if "main" in command or "master" in command:
            msg = "BLOCKING: Force push to main/master is not permitted in this project. Feature branches require human review via pull request. Rewrite the command without --force or target a different branch."
            print(msg, file=sys.stderr)
            return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

