import json
import sys
import subprocess

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    proj_root = "/private/var/folders/47/8h98svn929q45ld_8cvmn3kh0000gq/T/sic-eval-0kgtxm8d"
    if not file_path.startswith(proj_root):
        return 0

    try:
        result = subprocess.run(
            ["python", "-m", "pytest", "-x", "--tb=short"],
            capture_output=True,
            text=True,
            cwd=proj_root,
            timeout=30
        )

        if result.returncode != 0:
            msg = f"BLOCKING: Fix each test failure before responding:\n{result.stdout}"
            if result.stderr:
                msg += f"\n{result.stderr}"
            print(msg, file=sys.stderr)

    except subprocess.TimeoutExpired:
        print("BLOCKING: Tests timed out (>30s) — Do not stop. Investigate timeout.", file=sys.stderr)
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())
